external_knowledge:
- "glanced upon by the curious eyes" metaphorically refers to the number of times compounds were viewed;
- "average weight they carry in the molecular world" refers to the average molecular weight of the compounds;
- "year of the Water Rabbit" corresponds to the year 2023 in the Chinese zodiac system.

sql:
SELECT count(*) 
FROM compounds 
WHERE compound_type = 'organic';

SELECT compound_type, COUNT(*) AS compound_count
FROM compounds
GROUP BY compound_type;

SELECT COUNT(DISTINCT compound_id) AS flammable_compound_count 
FROM hazards 
WHERE hazard_name = 'flammable';

SELECT compound_id FROM compound_properties
UNION
SELECT compound_id FROM hazards;

external_knowledge:
- Molecular weight refers to the weight of a molecule, typically measured in atomic mass units (amu) or daltons (Da); 
- The metaphor of ships sailing the sea represents individual compounds or molecules in a database;
- The load of the ships symbolizes the molecular weight of the compounds.

sql:
SELECT COUNT(*), AVG(property_value) AS average_molecular_weight
FROM compound_properties
WHERE property_name = 'molecular weight';

SELECT COUNT(DISTINCT c.compound_id) AS unique_compounds_found_by_casrn
FROM compounds c
INNER JOIN casrns cr ON c.compound_id = cr.compound_id;

SELECT DISTINCT cp.preferred_name
FROM compounds cp
INNER JOIN hazards h ON cp.compound_id = h.compound_id;

SELECT DISTINCT compound_id
FROM access_logs
WHERE access_date >= DATE('now', '-1 month');

SELECT compound_id, preferred_name, qsar_ready_smiles
FROM compounds
ORDER BY preferred_name ASC;

SELECT COUNT(DISTINCT A.compound_id) AS total_compounds_found
FROM access_logs AS A
WHERE A.user_id = 1;
